/* LC558 OR quad-tree — build from grids then merge */
class Solution {
    Node* build(vector<vector<int>>& g, int x, int y, int len) {
        if (len == 1) return new Node(g[x][y], true, nullptr,nullptr,nullptr,nullptr);
        auto tl=build(g,x,y,len/2), tr=build(g,x,y+len/2,len/2);
        auto bl=build(g,x+len/2,y,len/2), br=build(g,x+len/2,y+len/2,len/2);
        if (tl->isLeaf&&tr->isLeaf&&bl->isLeaf&&br->isLeaf && tl->val==tr->val&&tl->val==bl->val&&tl->val==br->val)
            return new Node(tl->val,true,nullptr,nullptr,nullptr,nullptr);
        return new Node(false,false,tl,tr,bl,br);
    }
public:
    Node* intersect(Node* a, Node* b) {
        if (a->isLeaf) return a->val ? a : b;
        if (b->isLeaf) return b->val ? b : a;
        return new Node(true,false,
            intersect(a->topLeft,b->topLeft), intersect(a->topRight,b->topRight),
            intersect(a->bottomLeft,b->bottomLeft), intersect(a->bottomRight,b->bottomRight));
    }
};
